import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { ResponsiveContainer, AreaChart, Area } from 'recharts';
import { TrendingUp, TrendingDown } from 'lucide-react';
import '../../styles/financeCoin.css';

const CryptoItem = ({ coin }) => {
  // Görseldeki gibi her coin için farklı bir gradyan rengi belirleyelim
  const getColors = (pair) => {
    if (pair.includes('BTC')) return { stroke: '#f7931a', fill: 'rgba(247, 147, 26, 0.2)' };
    if (pair.includes('ETH')) return { stroke: '#627eea', fill: 'rgba(98, 126, 234, 0.2)' };
    if (pair.includes('SOL')) return { stroke: '#14f195', fill: 'rgba(20, 241, 149, 0.2)' };
    return { stroke: '#3b82f6', fill: 'rgba(59, 130, 246, 0.2)' };
  };

  const colors = getColors(coin.pair);

  return (
    <div className="crypto-card">
      <div className="coin-info">
        <div className="coin-name-box">
          <span className="coin-symbol">{coin.pair.replace('TRY', '')}</span>
          <span className="coin-full-name">{coin.pair}</span>
        </div>
        <div className="price-box">
          <span className="current-price">{parseFloat(coin.last).toLocaleString()} ₺</span>
          <span className={`change ${coin.dailyPercent >= 0 ? 'up' : 'down'}`}>
            {coin.dailyPercent >= 0 ? <TrendingUp size={14} /> : <TrendingDown size={14} />}
            %{Math.abs(coin.dailyPercent).toFixed(2)}
          </span>
        </div>
      </div>

      {/* Görseldeki grafik havasını vermek için küçük bir alan grafiği */}
      <div className="mini-chart">
        <ResponsiveContainer width="100%" height={50}>
          <AreaChart data={coin.chartData}>
            <Area 
              type="monotone" 
              dataKey="value" 
              stroke={colors.stroke} 
              fill={colors.fill} 
              strokeWidth={2}
            />
          </AreaChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
};

const FinanceCoin = () => {
  const [tickerData, setTickerData] = useState([]);

  const fetchData = async () => {
    try {
      const response = await axios.get('https://api.btcturk.com/api/v2/ticker');
      // Sadece ana coinleri filtreleyelim (BTC, ETH, SOL vb. TRY pariteleri)
      const filtered = response.data.data.filter(c => 
        ['BTCTRY', 'ETHTRY', 'SOLTRY', 'BNBTRY', 'ADATRY', 'XRPTRY'].includes(c.pair)
      ).map(c => ({
        ...c,
        // API'den gerçek geçmiş veri gelmediği için şimdilik rastgele küçük grafik verisi üretiyoruz
        chartData: Array.from({ length: 10 }, () => ({ value: Math.random() * 100 }))
      }));
      setTickerData(filtered);
    } catch (error) {
      console.error("Veri çekilemedi:", error);
    }
  };

  useEffect(() => {
    fetchData();
    const interval = setInterval(fetchData, 5000); // 5 saniyede bir güncelle
    return () => clearInterval(interval);
  }, []);

  return (
    <div className="market-container">
      <h2 className="market-title">CRYPTO MARKET INSIGHTS</h2>
      <div className="crypto-list">
        {tickerData.map((coin) => (
          <CryptoItem key={coin.pair} coin={coin} />
        ))}
      </div>
    </div>
  );
};

export default FinanceCoin;
